import{_ as e,o as t,c as r,ae as o}from"./chunks/framework.oH6zmTcc.js";const i="/atw-rpg/docs/screenshots/campaign-backstage-encounter.png",n="/atw-rpg/docs/screenshots/campaign-dashboard.png",s="/atw-rpg/docs/screenshots/campaign-list.png",c="/atw-rpg/docs/screenshots/campaign-list-universe-filter.png",h="/atw-rpg/docs/screenshots/campaign-backstage-encounter-outcome.png",p="/atw-rpg/docs/screenshots/campaign-promo-hooks.png",l="/atw-rpg/docs/screenshots/campaign-promo-outcome.png",m="/atw-rpg/docs/screenshots/campaign-beginning.png",g="/atw-rpg/docs/screenshots/campaign-tournament-bracket.png",d="/atw-rpg/docs/screenshots/campaign-tag-team.png",u="/atw-rpg/docs/screenshots/campaign-betrayal.png",b="/atw-rpg/docs/screenshots/campaign-fighting-champion.png",y="/atw-rpg/docs/screenshots/campaign-gang-warfare.png",f="/atw-rpg/docs/screenshots/campaign-corporate-power-trip.png",k="/atw-rpg/docs/screenshots/campaign-backstage-actions.png",w="/atw-rpg/docs/screenshots/campaign-story-journal.png",B=JSON.parse('{"title":"Campaign","description":"","frontmatter":{},"headers":[],"relativePath":"guide/campaign.md","filePath":"guide/campaign.md"}'),v={name:"guide/campaign.md"};function _(q,a,P,T,C,x){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="campaign" tabindex="-1">Campaign <a class="header-anchor" href="#campaign" aria-label="Permalink to &quot;Campaign&quot;">​</a></h1><p>Welcome to the Campaign guide. This documentation is automatically generated from the latest game features.</p><h2 id="backstage-encounters" tabindex="-1">Backstage Encounters <a class="header-anchor" href="#backstage-encounters" aria-label="Permalink to &quot;Backstage Encounters&quot;">​</a></h2><p>Random encounters can occur when you visit the backstage area. These interactive dialogue segments force you to make choices that affect your alignment and momentum.</p><p><img src="'+i+'" alt="Backstage Encounters"></p><hr><h2 id="campaign-dashboard" tabindex="-1">Campaign Dashboard <a class="header-anchor" href="#campaign-dashboard" aria-label="Permalink to &quot;Campaign Dashboard&quot;">​</a></h2><p>Track your wrestler&#39;s progress through the campaign. The alignment track shows your current position between Face and Heel, while the dashboard displays available actions and victory points.</p><p><img src="'+n+'" alt="Campaign Dashboard"></p><hr><h2 id="campaign-list" tabindex="-1">Campaign List <a class="header-anchor" href="#campaign-list" aria-label="Permalink to &quot;Campaign List&quot;">​</a></h2><p>The Campaign List gives admins a bird&#39;s-eye view of every active and completed campaign across the promotion. Each row shows the wrestler, current status, start date, and a direct link to the campaign dashboard.</p><p><img src="'+s+'" alt="Campaign List"></p><hr><h2 id="campaign-list-–-universe-scope" tabindex="-1">Campaign List – Universe Scope <a class="header-anchor" href="#campaign-list-–-universe-scope" aria-label="Permalink to &quot;Campaign List – Universe Scope&quot;">​</a></h2><p>The campaign list is scoped to the currently selected universe. Switching universes in the top toolbar immediately updates the grid to show only the campaigns belonging to that universe, keeping multi-universe promotions cleanly separated.</p><p><img src="'+c+'" alt="Campaign List – Universe Scope"></p><hr><h2 id="encounter-outcomes" tabindex="-1">Encounter Outcomes <a class="header-anchor" href="#encounter-outcomes" aria-label="Permalink to &quot;Encounter Outcomes&quot;">​</a></h2><p>Every choice in a backstage encounter has a narrative outcome and mechanical consequences, such as alignment shifts or bonuses for your next match.</p><p><img src="'+h+'" alt="Encounter Outcomes"></p><hr><h2 id="smart-promo-hooks" tabindex="-1">Smart Promo Hooks <a class="header-anchor" href="#smart-promo-hooks" aria-label="Permalink to &quot;Smart Promo Hooks&quot;">​</a></h2><p>The Smart Promo system uses AI to generate dynamic rhetorical hooks based on your wrestler&#39;s personality and current rivalries. Choose your strategy to connect with the audience or draw heat.</p><p><img src="'+p+'" alt="Smart Promo Hooks"></p><hr><h2 id="smart-promo-outcome" tabindex="-1">Smart Promo Outcome <a class="header-anchor" href="#smart-promo-outcome" aria-label="Permalink to &quot;Smart Promo Outcome&quot;">​</a></h2><p>Your choices have consequences. The crowd reaction, opponent retorts, and alignment shifts are all dynamically calculated, affecting your wrestler&#39;s momentum and reputation.</p><p><img src="'+l+'" alt="Smart Promo Outcome"></p><hr><h2 id="the-beginning" tabindex="-1">The Beginning <a class="header-anchor" href="#the-beginning" aria-label="Permalink to &quot;The Beginning&quot;">​</a></h2><p>Your journey starts here. Establish your reputation through backstage encounters and initial matches as you find your footing in All Time Wrestling.</p><p><img src="'+m+'" alt="The Beginning"></p><hr><h2 id="tournament-bracket" tabindex="-1">Tournament Bracket <a class="header-anchor" href="#tournament-bracket" aria-label="Permalink to &quot;Tournament Bracket&quot;">​</a></h2><p>The tournament chapter challenges you to climb the ranks in a single-elimination bracket. Win your matches to advance to the finals and claim the trophy.</p><p><img src="'+g+'" alt="Tournament Bracket"></p><hr><h2 id="tag-team-redemption" tabindex="-1">Tag Team Redemption <a class="header-anchor" href="#tag-team-redemption" aria-label="Permalink to &quot;Tag Team Redemption&quot;">​</a></h2><p>Experience the power of partnership. Find a compatible partner and dominate the tag team division while rebuilding your momentum.</p><p><img src="'+d+'" alt="Tag Team Redemption"></p><hr><h2 id="betrayal" tabindex="-1">Betrayal <a class="header-anchor" href="#betrayal" aria-label="Permalink to &quot;Betrayal&quot;">​</a></h2><p>Trust is a luxury you can no longer afford. Face the consequences of a broken alliance and seek retribution against your former partner.</p><p><img src="'+u+'" alt="Betrayal"></p><hr><h2 id="fighting-champion" tabindex="-1">Fighting Champion <a class="header-anchor" href="#fighting-champion" aria-label="Permalink to &quot;Fighting Champion&quot;">​</a></h2><p>As the Fighting Champion, you must defend your title against a series of challengers. Each defense increases your prestige but tests your stamina.</p><p><img src="'+b+'" alt="Fighting Champion"></p><hr><h2 id="gang-warfare" tabindex="-1">Gang Warfare <a class="header-anchor" href="#gang-warfare" aria-label="Permalink to &quot;Gang Warfare&quot;">​</a></h2><p>In Gang Warfare, you must navigate the dangerous world of factions. Build alliances or crush rivals as you fight for control of the locker room.</p><p><img src="'+y+'" alt="Gang Warfare"></p><hr><h2 id="corporate-power-trip" tabindex="-1">Corporate Power Trip <a class="header-anchor" href="#corporate-power-trip" aria-label="Permalink to &quot;Corporate Power Trip&quot;">​</a></h2><p>The authorities are against you. Survive impossible odds and unfair stipulations as you challenge the corrupt management&#39;s control.</p><p><img src="'+f+'" alt="Corporate Power Trip"></p><hr><h2 id="backstage-actions" tabindex="-1">Backstage Actions <a class="header-anchor" href="#backstage-actions" aria-label="Permalink to &quot;Backstage Actions&quot;">​</a></h2><p>Take daily actions to improve your stats, recover from injuries, or build hype for your next match. Choose wisely, as you have limited time each day.</p><p><img src="'+k+'" alt="Backstage Actions"></p><hr><h2 id="story-journal" tabindex="-1">Story Journal <a class="header-anchor" href="#story-journal" aria-label="Permalink to &quot;Story Journal&quot;">​</a></h2><p>Your AI-generated adventures are preserved in the Story Journal. Here you can review past storyline arcs and download them as JSON chapter files to share or preserve.</p><p><img src="'+w+'" alt="Story Journal"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="skill-upgrades" tabindex="-1">Skill Upgrades <a class="header-anchor" href="#skill-upgrades" aria-label="Permalink to &quot;Skill Upgrades&quot;">​</a></h3><p>The upgrade moves to Purchased Skills and takes effect immediately — maximum stamina increased by 2 for all future matches. The effective stats shown on your Player Dashboard update to reflect the new total.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/campaign-skill-upgrades.mp4" type="video/mp4"></video><hr><h3 id="campaign-flow-and-backstage-actions" tabindex="-1">Campaign Flow and Backstage Actions <a class="header-anchor" href="#campaign-flow-and-backstage-actions" aria-label="Permalink to &quot;Campaign Flow and Backstage Actions&quot;">​</a></h3><p>Back on the Campaign Dashboard — Victory Points accumulate from backstage actions and match wins, driving chapter progression throughout the season. Reaching each VP threshold automatically transitions the story to the next chapter.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/campaign-backstage-actions.mp4" type="video/mp4"></video><hr><h3 id="corporate-power-trip-chapter" tabindex="-1">Corporate Power Trip Chapter <a class="header-anchor" href="#corporate-power-trip-chapter" aria-label="Permalink to &quot;Corporate Power Trip Chapter&quot;">​</a></h3><p>Corporate Power Trip triggers at 15 Victory Points — the player has earned enough momentum to challenge the establishment and climb to the top of the card. VP accumulates from match wins, backstage actions, and completed milestones.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/campaign-corporate-power-trip.mp4" type="video/mp4"></video><hr><h3 id="gang-warfare-chapter" tabindex="-1">Gang Warfare Chapter <a class="header-anchor" href="#gang-warfare-chapter" aria-label="Permalink to &quot;Gang Warfare Chapter&quot;">​</a></h3><p>Gang Warfare unlocks when factions collide for territory control — the chapter sets up a faction turf war storyline across multiple shows, with backstage actions that let the player recruit allies or sabotage rivals.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/campaign-gang-warfare.mp4" type="video/mp4"></video><hr><h3 id="the-fighting-champion-chapter" tabindex="-1">The Fighting Champion Chapter <a class="header-anchor" href="#the-fighting-champion-chapter" aria-label="Permalink to &quot;The Fighting Champion Chapter&quot;">​</a></h3><p>The Fighting Champion chapter activates when the player holds a championship. The campaign tracks title reigns automatically and unlocks this chapter, presenting unique storyline choices available only to a defending champion.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/campaign-fighting-champion.mp4" type="video/mp4"></video><hr><h3 id="campaign-list-walkthrough" tabindex="-1">Campaign List Walkthrough <a class="header-anchor" href="#campaign-list-walkthrough" aria-label="Permalink to &quot;Campaign List Walkthrough&quot;">​</a></h3><p>The Campaign Dashboard shows the wrestler&#39;s current chapter, alignment track, win/loss record, and available actions — giving admins full visibility into any player&#39;s campaign state.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/campaign-list-walkthrough.mp4" type="video/mp4"></video><hr>',91)])])}const W=e(v,[["render",_]]);export{B as __pageData,W as default};
